use aiken/collection/list
use aiken/fuzz
use cardano/assets.{lovelace_of}
use cardano/transaction.{Output, OutputReference, Transaction}
pub type CdpDatum {
  owner:             ByteArray,
  collateral:        Int,
  debt:              Int,
  liquidation_ratio: Int,
  bonus_percent:     Int,
}

pub type CdpRedeemer {
  Repay
  Liquidate
}

fn is_undercollateralized(collateral: Int, debt: Int, ratio: Int) -> Bool {
  debt > 0 && collateral * 100 < debt * ratio
}

/// Liquidator pays discounted debt: debt * (100 - bonus_percent) / 100
fn discounted_debt(debt: Int, bonus_percent: Int) -> Int {
  debt * (100 - bonus_percent) / 100
}

fn liquidator_pays_discounted(
  outputs:       List<Output>,
  owner_addr:    Output,
  debt:          Int,
  bonus_percent: Int,
) -> Bool {
  let required = discounted_debt(debt, bonus_percent)
  let paid =
    list.foldl(
      outputs,
      0,
      fn(o, acc) {
        if o.address == owner_addr.address {
          acc + lovelace_of(o.value)
        } else {
          acc
        }
      },
    )
  paid >= required
}

validator cdp_liquidation_bonus {
  spend(
    datum: Option<CdpDatum>,
    redeemer: CdpRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Repay -> list.has(self.extra_signatories, d.owner)
      Liquidate ->
        is_undercollateralized(d.collateral, d.debt, d.liquidation_ratio)
    }
  }
}

// в”Ђв”Ђ Property tests в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

test prop_discounted_debt_zero_bonus(debt via fuzz.int_at_least(1)) {
  discounted_debt(debt, 0) == debt
}

test prop_discounted_debt_less_than_full(
  vals via fuzz.both(fuzz.int_at_least(100), fuzz.int_between(1, 50)),
) {
  let (debt, bonus) = vals
  discounted_debt(debt, bonus) < debt
}

test prop_discounted_debt_non_negative(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_between(0, 99)),
) {
  let (debt, bonus) = vals
  discounted_debt(debt, bonus) >= 0
}

test prop_undercollateralized_below_ratio(debt via fuzz.int_at_least(1)) {
  is_undercollateralized(debt * 119, debt * 100, 120)
}

// в”Ђв”Ђ Negative (fail) tests в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

// A position is NOT undercollateralized when debt is zero вЂ”
// is_undercollateralized requires debt > 0, so this must always return False.
test prop_zero_debt_never_undercollateralized(
  collateral via fuzz.int_at_least(0),
) fail {
  expect is_undercollateralized(collateral, 0, 150)
}

// A well-collateralized position (collateral * 100 >= debt * ratio) must NOT
// be flagged as undercollateralized.  Here collateral = debt * ratio ensures
// the product is exactly at the threshold (>=), so the strict inequality fails.
test prop_fully_collateralized_not_undercollateralized(
  debt via fuzz.int_at_least(1),
) fail {
  // collateral * 100 == debt * ratio  в†’  NOT (collateral * 100 < debt * ratio)
  expect is_undercollateralized(debt * 150, debt * 100, 150)
}

// liquidator_pays_discounted with an empty output list always yields paid = 0.
// For any positive required amount the check must fail.
test prop_no_outputs_liquidator_fails(
  debt via fuzz.int_at_least(1),
) fail {
  // required = discounted_debt(debt, 0) = debt >= 1, paid = 0  в†’  False
  expect liquidator_pays_discounted([], Output { address: ..., value: assets.zero, datum: NoDatum, reference_script: None }, debt, 0)
}

// Over-100% bonus makes discounted_debt negative; but even with bonus = 99
// and debt = 1, required = 0, so we pick bonus = 0 and collateral too low.
// Simpler: collateral exactly at ratio boundary means NOT strictly under.
// Use collateral * 100 > debt * ratio to guarantee it is well collateralised.
test prop_overcollateralized_not_undercollateralized(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_between(1, 10)),
) fail {
  let (debt, extra) = vals
  // collateral = debt * 150 + extra  в†’  collateral * 100 > debt * 150 * 100 / 100
  // i.e. (debt*150 + extra)*100 > debt*150  always true, so NOT undercollateralized
  expect is_undercollateralized(debt * 150 + extra, debt * 100, 150)
}

use aiken/collection/list
use aiken/fuzz
use cardano/assets.{lovelace_of}
use cardano/transaction.{Output, OutputReference, Transaction}
pub type CdpDatum {
  owner:             ByteArray,
  collateral:        Int,
  debt:              Int,
  liquidation_ratio: Int,
  min_collateral:    Int,
}

pub type CdpRedeemer {
  Repay
  Liquidate
}

fn is_undercollateralized(collateral: Int, debt: Int, ratio: Int) -> Bool {
  debt > 0 && collateral * 100 < debt * ratio
}

/// Position must have at least min_collateral to be liquidatable (dust guard)
fn is_liquidatable(
  collateral:     Int,
  debt:           Int,
  ratio:          Int,
  min_collateral: Int,
) -> Bool {
  collateral >= min_collateral && is_undercollateralized(collateral, debt, ratio)
}

fn liquidator_pays_debt(
  outputs:       List<Output>,
  owner_addr:    Output,
  debt_lovelace: Int,
) -> Bool {
  let paid =
    list.foldl(
      outputs,
      0,
      fn(o, acc) {
        if o.address == owner_addr.address {
          acc + lovelace_of(o.value)
        } else {
          acc
        }
      },
    )
  paid >= debt_lovelace
}

validator cdp_dust_guard {
  spend(
    datum: Option<CdpDatum>,
    redeemer: CdpRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Repay -> list.has(self.extra_signatories, d.owner)
      Liquidate ->
        is_liquidatable(
          d.collateral,
          d.debt,
          d.liquidation_ratio,
          d.min_collateral,
        )
    }
  }
}

// в”Ђв”Ђ Property tests в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

test prop_dust_guard_undercollateralized_above_min(debt via fuzz.int_at_least(1)) {
  let collateral = debt * 119
  is_liquidatable(collateral, debt * 100, 120, 1)
}

test prop_dust_guard_below_min_not_liquidatable(debt via fuzz.int_at_least(1)) {
  let collateral = debt * 119
  !is_liquidatable(collateral, debt * 100, 120, collateral + 1)
}

test prop_dust_guard_overcollateralized_not_liquidatable(debt via fuzz.int_at_least(1)) {
  !is_liquidatable(debt * 150, debt * 100, 120, 1)
}

test prop_undercollateralized_inverse(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_at_least(1)),
) {
  let (collateral, debt) = vals
  let ratio = 150
  !(is_undercollateralized(collateral, debt, ratio) && collateral * 100 >= debt * ratio)
}

// в”Ђв”Ђ Negative / fail tests в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

// A well-collateralized position (collateral * 100 >= debt * ratio) must NOT be
// flagged as undercollateralized. Picking collateral = debt * ratio guarantees
// collateral * 100 == debt * ratio * 100 >= debt * ratio for any ratio >= 1.
test prop_overcollateralized_not_undercollateralized(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_between(1, 200)),
) fail {
  let (debt, ratio) = vals
  // collateral * 100 == debt * ratio * 100 >= debt * ratio  в†’  always False
  expect is_undercollateralized(debt * ratio, debt, ratio)
}

// Zero debt means the position can never be undercollateralized regardless of
// collateral or ratio. is_undercollateralized requires debt > 0.
test prop_zero_debt_not_undercollateralized(
  vals via fuzz.both(fuzz.int_at_least(0), fuzz.int_between(1, 500)),
) fail {
  let (collateral, ratio) = vals
  expect is_undercollateralized(collateral, 0, ratio)
}

// A position below min_collateral (dust) must NOT be liquidatable even when it
// is genuinely undercollateralized. We pick collateral < min_collateral by
// setting min_collateral = collateral + 1.
test prop_dust_position_not_liquidatable(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) fail {
  let (collateral, debt) = vals
  // ratio=200 means collateral*100 < debt*200 whenever collateral < debt*2.
  // We pick debt such that collateral < debt*2 by using debt = collateral + 1.
  // min_collateral = collateral + 1 > collateral, so dust guard fires.
  expect is_liquidatable(collateral, collateral + 1, 200, collateral + 1)
}

// liquidator_pays_debt with an empty output list must always return False when
// a positive debt is required, because paid = 0 < debt_lovelace.
test prop_no_outputs_fails_debt_check(
  debt_lovelace via fuzz.int_at_least(1),
) fail {
  // We need a dummy Output to pass as owner_addr; its address is irrelevant
  // because the outputs list is empty and foldl never executes.
  let dummy_output =
    Output {
      address: cardano/address.from_verification_key(#"deadbeef"),
      value: cardano/assets.zero,
      datum: cardano/transaction.NoDatum,
      reference_script: None,
    }
  expect liquidator_pays_debt([], dummy_output, debt_lovelace)
}

use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use aiken/fuzz
use cardano/address
use cardano/assets.{PolicyId, quantity_of}
use cardano/fuzz as cfuzz
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}
pub type State {
  Idle
  Active
  Locked
  Closing
}

pub type StateRedeemer {
  Advance
  Reset
  Terminate
}

pub type MachineDatum {
  state:        State,
  admin:        VerificationKeyHash,
  beacon_policy: PolicyId,
  beacon_name:  ByteArray,
}

/// Valid transitions: Idleв†’Active, Activeв†’Locked, Lockedв†’Closing
fn valid_transition(from: State, to: State, redeemer: StateRedeemer) -> Bool {
  when redeemer is {
    Advance ->
      when from is {
        Idle    -> to == Active
        Active  -> to == Locked
        Locked  -> to == Closing
        Closing -> False
      }
    Reset     -> to == Idle
    Terminate -> to == Closing
  }
}

/// The beacon NFT must be present in the continuing output
fn beacon_preserved(
  outputs:      List<Output>,
  own_addr:     address.Address,
  beacon_policy: PolicyId,
  beacon_name:  ByteArray,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      o.address == own_addr
        && quantity_of(o.value, beacon_policy, beacon_name) == 1
    },
  )
}

fn state_from_output(output: Output) -> Option<MachineDatum> {
  when output.datum is {
    InlineDatum(raw) -> {
      expect d: MachineDatum = raw
      Some(d)
    }
    _ -> None
  }
}

validator beacon_state_machine {
  spend(
    datum: Option<MachineDatum>,
    redeemer: StateRedeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    // Find own input to get address
    expect Some(own_input) =
      list.find(self.inputs, fn(i) { i.output_reference == own_ref })
    let own_addr = own_input.output.address
    // Find continuing output with new datum
    expect Some(next_output) =
      list.find(self.outputs, fn(o) { o.address == own_addr })
    expect Some(next_d) = state_from_output(next_output)
    // Validate
    valid_transition(d.state, next_d.state, redeemer)
      && beacon_preserved(self.outputs, own_addr, d.beacon_policy, d.beacon_name)
      && (
        when redeemer is {
          Advance -> True
          Reset   -> list.has(self.extra_signatories, d.admin)
          Terminate -> list.has(self.extra_signatories, d.admin)
        }
      )
  }
}

// в”Ђв”Ђ Property tests в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

test prop_valid_transition_advance_idle() {
  valid_transition(Idle, Active, Advance)
}

test prop_valid_transition_advance_active() {
  valid_transition(Active, Locked, Advance)
}

test prop_valid_transition_advance_locked() {
  valid_transition(Locked, Closing, Advance)
}

test prop_valid_transition_closing_advance_fails() {
  !valid_transition(Closing, Idle, Advance)
}

test prop_valid_transition_reset_always_to_idle() {
  valid_transition(Active, Idle, Reset)
    && valid_transition(Locked, Idle, Reset)
    && valid_transition(Closing, Idle, Reset)
}

test prop_valid_transition_wrong_target_fails() {
  !valid_transition(Idle, Locked, Advance)
}

// в”Ђв”Ђ Negative / fail tests в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

/// Closing state can never Advance to any next state
test prop_closing_advance_always_fails() fail {
  expect valid_transition(Closing, Closing, Advance)
}

/// Idleв†’Locked is not a valid Advance step (must go Idleв†’Active)
test prop_idle_to_locked_advance_fails() fail {
  expect valid_transition(Idle, Locked, Advance)
}

/// Reset must always transition to Idle; any other target is invalid
test prop_reset_non_idle_target_fails() fail {
  expect valid_transition(Active, Closing, Reset)
}

/// beacon_preserved always fails when the outputs list is empty,
/// regardless of policy / name requested
test prop_beacon_preserved_empty_outputs_fails(
  own_addr via cfuzz.address(),
  policy via cfuzz.policy_id(),
  name via cfuzz.asset_name(),
) fail {
  expect beacon_preserved([], own_addr, policy, name)
}

use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use aiken/fuzz
use cardano/address
use cardano/assets.{PolicyId, quantity_of}
use cardano/fuzz as cfuzz
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}
pub type ApprovalState {
  Draft
  Review
  Approved
  Rejected
}

pub type ApprovalRedeemer {
  Submit
  Approve
  Reject
  Revise
}

pub type ApprovalDatum {
  state:         ApprovalState,
  admin:         VerificationKeyHash,
  beacon_policy: PolicyId,
  beacon_name:   ByteArray,
}

fn valid_approval_transition(
  from:     ApprovalState,
  to:       ApprovalState,
  redeemer: ApprovalRedeemer,
) -> Bool {
  when redeemer is {
    Submit  -> from == Draft && to == Review
    Approve -> from == Review && to == Approved
    Reject  -> from == Review && to == Rejected
    Revise  -> from == Rejected && to == Draft
  }
}

fn beacon_preserved(
  outputs:       List<Output>,
  own_addr:      address.Address,
  beacon_policy: PolicyId,
  beacon_name:   ByteArray,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      o.address == own_addr
        && quantity_of(o.value, beacon_policy, beacon_name) == 1
    },
  )
}

fn datum_from_output(output: Output) -> Option<ApprovalDatum> {
  when output.datum is {
    InlineDatum(raw) -> {
      expect d: ApprovalDatum = raw
      Some(d)
    }
    _ -> None
  }
}

validator beacon_approval {
  spend(
    datum: Option<ApprovalDatum>,
    redeemer: ApprovalRedeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    expect Some(own_input) =
      list.find(self.inputs, fn(i) { i.output_reference == own_ref })
    let own_addr = own_input.output.address
    expect Some(next_output) =
      list.find(self.outputs, fn(o) { o.address == own_addr })
    expect Some(next_d) = datum_from_output(next_output)
    valid_approval_transition(d.state, next_d.state, redeemer)
      && beacon_preserved(self.outputs, own_addr, d.beacon_policy, d.beacon_name)
      && list.has(self.extra_signatories, d.admin)
  }
}

// в”Ђв”Ђ Property tests в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

test prop_submit_draft_to_review() {
  valid_approval_transition(Draft, Review, Submit)
}

test prop_approve_review_to_approved() {
  valid_approval_transition(Review, Approved, Approve)
}

test prop_reject_review_to_rejected() {
  valid_approval_transition(Review, Rejected, Reject)
}

test prop_revise_rejected_to_draft() {
  valid_approval_transition(Rejected, Draft, Revise)
}

// в”Ђв”Ђ Negative / fail tests в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

// Submit requires Draft -> Review; using Approved as `from` always fails.
test prop_submit_wrong_from_state_rejected() fail {
  expect valid_approval_transition(Approved, Review, Submit)
}

// Approve requires Review -> Approved; starting from Draft always fails.
test prop_approve_wrong_from_state_rejected() fail {
  expect valid_approval_transition(Draft, Approved, Approve)
}

// Revise requires Rejected -> Draft; starting from Review always fails.
test prop_revise_wrong_from_state_rejected() fail {
  expect valid_approval_transition(Review, Draft, Revise)
}

// beacon_preserved with an empty output list always returns False.
test prop_beacon_preserved_no_outputs_rejected(
  policy via cfuzz.policy_id(),
  name via cfuzz.asset_name(),
  addr via cfuzz.address(),
) fail {
  expect beacon_preserved([], addr, policy, name)
}

use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use aiken/fuzz
use cardano/address
use cardano/assets.{PolicyId, quantity_of}
use cardano/fuzz as cfuzz
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}
pub type Step {
  Step0
  Step1
  Step2
  Step3
}

pub type StepRedeemer {
  Next
  Rollback
  Abort
}

pub type StepDatum {
  step:          Step,
  admin:         VerificationKeyHash,
  beacon_policy: PolicyId,
  beacon_name:   ByteArray,
}

/// Next advances, Rollback goes one step back, Abort resets to Step0
fn valid_step_transition(from: Step, to: Step, redeemer: StepRedeemer) -> Bool {
  when redeemer is {
    Next ->
      when from is {
        Step0 -> to == Step1
        Step1 -> to == Step2
        Step2 -> to == Step3
        Step3 -> False
      }
    Rollback ->
      when from is {
        Step0 -> False
        Step1 -> to == Step0
        Step2 -> to == Step1
        Step3 -> to == Step2
      }
    Abort -> to == Step0
  }
}

fn beacon_preserved(
  outputs:       List<Output>,
  own_addr:      address.Address,
  beacon_policy: PolicyId,
  beacon_name:   ByteArray,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      o.address == own_addr
        && quantity_of(o.value, beacon_policy, beacon_name) == 1
    },
  )
}

fn datum_from_output(output: Output) -> Option<StepDatum> {
  when output.datum is {
    InlineDatum(raw) -> {
      expect d: StepDatum = raw
      Some(d)
    }
    _ -> None
  }
}

validator beacon_rollback {
  spend(
    datum: Option<StepDatum>,
    redeemer: StepRedeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    expect Some(own_input) =
      list.find(self.inputs, fn(i) { i.output_reference == own_ref })
    let own_addr = own_input.output.address
    expect Some(next_output) =
      list.find(self.outputs, fn(o) { o.address == own_addr })
    expect Some(next_d) = datum_from_output(next_output)
    valid_step_transition(d.step, next_d.step, redeemer)
      && beacon_preserved(self.outputs, own_addr, d.beacon_policy, d.beacon_name)
  }
}

